import{_ as t,D as a,o as c,c as d,I as o,R as r,k as e,a as i}from"./chunks/framework.ndjtv7DT.js";const F=JSON.parse('{"title":"BFC","description":"","frontmatter":{},"headers":[],"relativePath":"cheat-sheets/css/bfc.md","filePath":"cheat-sheets/css/bfc.md","lastUpdated":1692688673000}'),n={name:"cheat-sheets/css/bfc.md"},s=r('<h1 id="bfc" tabindex="-1">BFC <a class="header-anchor" href="#bfc" aria-label="Permalink to &quot;BFC&quot;">​</a></h1><h2 id="bfc-是什么" tabindex="-1">BFC 是什么 <a class="header-anchor" href="#bfc-是什么" aria-label="Permalink to &quot;BFC 是什么&quot;">​</a></h2><p>BFC 即 Block Formatting Context，中文名是块级格式化上下文。</p><p>BFC 是页面内的迷你布局，是一块独立的渲染区域，具有独立的渲染规则。</p><h2 id="bfc-的特点" tabindex="-1">BFC 的特点 <a class="header-anchor" href="#bfc-的特点" aria-label="Permalink to &quot;BFC 的特点&quot;">​</a></h2><ul><li>BFC 会形成⼀个独⽴空间，内外元素不会相互影响。</li><li>BFC 内部块级元素垂直排列。</li><li>BFC 内部相邻块级元素外边距重叠（即外边距塌陷，margin collapsing）。</li><li>BFC 不会与外部浮动元素重叠。</li><li>BFC 会包含内部浮动元素，排除外部浮动元素，抑制与外部元素的外边距重叠。</li><li>BFC 高度会包含内部浮动元素高度。</li></ul><h2 id="怎么建立-bfc" tabindex="-1">怎么建立 BFC <a class="header-anchor" href="#怎么建立-bfc" aria-label="Permalink to &quot;怎么建立 BFC&quot;">​</a></h2><h3 id="常用" tabindex="-1">常用 <a class="header-anchor" href="#常用" aria-label="Permalink to &quot;常用&quot;">​</a></h3><ul><li>页面根元素 <code>&lt;html&gt;&lt;/html&gt;</code></li><li>浮动元素，<code>float</code> 值为 <code>left</code> 或 <code>right</code><ul><li><code>float: left</code></li><li><code>float: right</code></li></ul></li><li>绝对定位元素 <ul><li><code>position: absolute</code></li><li><code>position: fixed</code></li></ul></li><li>内联块级元素 <ul><li><code>display: inline-block</code></li></ul></li><li>表格相关 <ul><li>表格 <code>display: table</code></li><li>内联表格 <code>display: inline-table</code></li><li>表格行组 <code>display: table-row-group</code>，表现为 <code>&lt;tbody&gt;&lt;tbody&gt;</code></li><li>表格头组 <code>display: table-header-group</code>，表现为 <code>&lt;thead&gt;&lt;/thead&gt;</code></li><li>表格尾组 <code>display: table-footer-group</code>，表现为 <code>&lt;tfoot&gt;&lt;/tfoot&gt;</code></li><li>表格行 <code>display: table-row</code>，表现为 <code>&lt;tr&gt;&lt;/tr&gt;</code></li><li>表格单元格 <code>display: table-cell</code>，表现为 <code>&lt;td&gt;&lt;/td&gt;</code></li><li>表格标题 <code>display: table-caption</code>，表现为 <code>&lt;caption&gt;&lt;caption&gt;</code></li></ul></li><li>块级元素，且 <code>overflow</code> 的值不是 <code>visible</code> 或 <code>clip</code><ul><li><code>overflow: auto</code></li><li><code>overflow: hidden</code></li><li><code>overflow: scroll</code></li></ul></li></ul><h3 id="少见" tabindex="-1">少见 <a class="header-anchor" href="#少见" aria-label="Permalink to &quot;少见&quot;">​</a></h3><ul><li>浮动元素，<code>float</code> 值为 <code>inline-start</code> 或 <code>inline-end</code><ul><li><code>float: inline-start</code></li><li><code>float: inline-end</code></li></ul></li><li>直接声明 BFC <ul><li><code>display: flow-root</code></li></ul></li><li>设置 <code>contain</code> 为 <code>layout</code>、<code>content</code> 或 <code>paint</code> 的元素 <ul><li><code>contain: layout</code></li><li><code>contain: content</code></li><li><code>contain: paint</code></li></ul></li><li>flex 项目 <ul><li><code>display: flex</code> 或 <code>display: inline-flex</code> 元素的直接子元素</li><li>本身不是 flex 容器、 grid 容器或 table 容器</li></ul></li><li>grid 项目 <ul><li><code>display: grid</code> 或 <code>display: inline-grid</code> 元素的直接子元素</li><li>本身不是 flex 容器、 grid 容器或 table 容器</li></ul></li><li>多列容器 <ul><li><code>column-count</code> 或 <code>column-width</code> 不是 auto</li></ul></li><li><code>column-span: all</code></li></ul><h3 id="边缘情况" tabindex="-1">边缘情况 <a class="header-anchor" href="#边缘情况" aria-label="Permalink to &quot;边缘情况&quot;">​</a></h3><p>flex 容器 / grid 容器会建立一个新的 flex / grid 格式化上下文，除了布局之外，它与块格式化上下文类似。</p><p>flex / grid 容器内没有可用的浮动元素，但仍会排除外部浮动元素，抑制外边距折叠。</p><h2 id="应用" tabindex="-1">应用 <a class="header-anchor" href="#应用" aria-label="Permalink to &quot;应用&quot;">​</a></h2><h3 id="包含内部浮动元素" tabindex="-1">包含内部浮动元素 <a class="header-anchor" href="#包含内部浮动元素" aria-label="Permalink to &quot;包含内部浮动元素&quot;">​</a></h3>',16),h=e("h3",{id:"排除外部浮动元素-双列布局",tabindex:"-1"},[i("排除外部浮动元素 / 双列布局 "),e("a",{class:"header-anchor",href:"#排除外部浮动元素-双列布局","aria-label":'Permalink to "排除外部浮动元素 / 双列布局"'},"​")],-1),u=e("h3",{id:"抑制外边距折叠",tabindex:"-1"},[i("抑制外边距折叠 "),e("a",{class:"header-anchor",href:"#抑制外边距折叠","aria-label":'Permalink to "抑制外边距折叠"'},"​")],-1),f=e("h2",{id:"参考",tabindex:"-1"},[i("参考 "),e("a",{class:"header-anchor",href:"#参考","aria-label":'Permalink to "参考"'},"​")],-1),b=e("ul",null,[e("li",null,[e("a",{href:"https://developer.mozilla.org/en-US/docs/Web/Guide/CSS/Block_formatting_context",target:"_blank",rel:"noreferrer"},"MDN > References > Developer Guides > Block Formatting Context")]),e("li",null,[e("a",{href:"https://www.smashingmagazine.com/2017/12/understanding-css-layout-block-formatting-context/",target:"_blank",rel:"noreferrer"},"Understanding CSS Layout And The Block Formatting Context")])],-1);function p(m,g,_,x,k,C){const l=a("VEmbed");return c(),d("div",null,[s,o(l,{src:"https://stackblitz.com/edit/vitejs-vite-j7mtud?embed=1&file=src%2FApp.vue"}),h,o(l,{src:"https://stackblitz.com/edit/vitejs-vite-hexaow?embed=1&file=src%2FApp.vue"}),u,o(l,{src:"https://stackblitz.com/edit/vitejs-vite-3am1ff?embed=1&file=src%2FApp.vue"}),f,b])}const y=t(n,[["render",p]]);export{F as __pageData,y as default};
